namespace BlazorApp.Services;

public class NotificationItem
{
    public int Id { get; set; }
    public string Message { get; set; } = "";
    public DateTime Timestamp { get; set; }
}

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<NotificationItem> _notifications = new();
    private readonly Lock _lock = new();

    public NotificationService()
    {
        // Seed with initial fake data.
        _notifications.AddRange(new[]
        {
            new NotificationItem { Id = _nextId++, Message = "Welcome to the app!", Timestamp = DateTime.UtcNow.AddMinutes(-10) },
            new NotificationItem { Id = _nextId++, Message = "Your profile was updated.", Timestamp = DateTime.UtcNow.AddMinutes(-5) },
            new NotificationItem { Id = _nextId++, Message = "New feature: dark mode is available.", Timestamp = DateTime.UtcNow.AddMinutes(-1) },
        });
    }

    /// <summary>Returns all notifications.</summary>
    public Task<List<NotificationItem>> GetNotificationsAsync()
    {
        lock (_lock)
        {
            return Task.FromResult(_notifications.OrderByDescending(n => n.Timestamp).ToList());
        }
    }

    /// <summary>Returns only notifications newer than the given id.</summary>
    public Task<List<NotificationItem>> GetNotificationsSinceAsync(int lastSeenId)
    {
        lock (_lock)
        {
            var newer = _notifications
                .Where(n => n.Id > lastSeenId)
                .OrderByDescending(n => n.Timestamp)
                .ToList();
            return Task.FromResult(newer);
        }
    }

    /// <summary>Simulates an external system pushing a new notification.</summary>
    public void AddRandom()
    {
        string[] templates =
        [
            "You have a new follower.",
            "Your report is ready to download.",
            "Scheduled maintenance tonight at 11 PM.",
            "Someone commented on your post.",
            "Your subscription renews soon.",
        ];

        lock (_lock)
        {
            var msg = templates[Random.Shared.Next(templates.Length)];
            _notifications.Add(new NotificationItem
            {
                Id = _nextId++,
                Message = msg,
                Timestamp = DateTime.UtcNow,
            });
        }
    }
}

@page "/notifications"
@rendermode InteractiveServer
@using BlazorApp.Services
@inject NotificationService Svc
@implements IAsyncDisposable

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    @if (_notifications is not null)
    {
        <span class="badge bg-primary rounded-pill ms-2">@_notifications.Count</span>
    }
</h1>

@if (_notifications is null)
{
    <p><em>Loading…</em></p>
}
else if (_notifications.Count == 0)
{
    <p>No notifications yet.</p>
}
else
{
    <ul class="list-group">
        @foreach (var n in _notifications)
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <span>@n.Message</span>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<NotificationItem>? _notifications;
    private int _lastSeenId;
    private CancellationTokenSource? _cts;

    [PersistentState]
    public List<NotificationItem>? PersistedNotifications { get; set; }

    [PersistentState]
    public int PersistedLastSeenId { get; set; }

    protected override async Task OnInitializedAsync()
    {
        // Restore persisted state from prerender, or fetch fresh.
        if (PersistedNotifications is not null)
        {
            _notifications = PersistedNotifications;
            _lastSeenId = PersistedLastSeenId;
        }
        else
        {
            _notifications = await Svc.GetNotificationsAsync();
            _lastSeenId = _notifications.Count > 0 ? _notifications.Max(n => n.Id) : 0;

            // Save for the interactive render.
            PersistedNotifications = _notifications;
            PersistedLastSeenId = _lastSeenId;
        }
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // Only runs once the page is truly interactive — never during prerender.
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(5), ct);

            // Simulate external activity so there's something new to find.
            Svc.AddRandom();

            var newer = await Svc.GetNotificationsSinceAsync(_lastSeenId);
            if (newer.Count > 0)
            {
                _notifications = newer.Concat(_notifications!).ToList();
                _lastSeenId = _notifications.Max(n => n.Id);
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
        }
    }
}

